import{_ as t,o,c as i,a2 as a}from"./chunks/framework.Crpw6aS5.js";const g=JSON.parse('{"title":"Settings","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/settings.md","filePath":"en/guide/settings.md"}'),n={name:"en/guide/settings.md"};function r(l,e,s,c,h,d){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h1><p>The <strong>Settings</strong> page centralizes your account configuration, security, webhooks, and preferences.</p><hr><h2 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to &quot;Profile&quot;">​</a></h2><p>The profile section displays your information:</p><ul><li><strong>Email</strong>: your sign-in email address</li><li><strong>Display name</strong>: editable (automatically retrieved from Google SSO)</li><li><strong>Avatar</strong>: retrieved from Google SSO when available</li><li><strong>Role</strong>: User or Administrator</li></ul><hr><h2 id="connected-gmail-accounts" tabindex="-1">Connected Gmail Accounts <a class="header-anchor" href="#connected-gmail-accounts" aria-label="Permalink to &quot;Connected Gmail Accounts&quot;">​</a></h2><p>List of all your Gmail accounts linked to Nid:</p><ul><li>Email of each account</li><li>Connection status (active / inactive)</li><li><strong>Connect a Gmail account</strong> button to add a new one</li><li><strong>Disconnect</strong> button to remove an account</li></ul><blockquote><p>📸 <em>Suggested screenshot: Gmail Accounts section with the account list and connect/disconnect buttons</em></p></blockquote><hr><h2 id="two-factor-authentication-2fa" tabindex="-1">Two-Factor Authentication (2FA) <a class="header-anchor" href="#two-factor-authentication-2fa" aria-label="Permalink to &quot;Two-Factor Authentication (2FA)&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Local accounts only</p><p>2FA only applies to local accounts (email + password). Google SSO users are protected by Google&#39;s own 2FA.</p></div><h3 id="enable-2fa" tabindex="-1">Enable 2FA <a class="header-anchor" href="#enable-2fa" aria-label="Permalink to &quot;Enable 2FA&quot;">​</a></h3><ol><li>Click <strong>Set up 2FA</strong></li><li>A <strong>QR code</strong> is displayed</li><li>Scan it with your authenticator app (Google Authenticator, Authy, Microsoft Authenticator, etc.)</li><li>Enter the 6-digit code shown by the app</li><li>Click <strong>Verify and Enable</strong></li></ol><blockquote><p>📸 <em>Suggested screenshot: 2FA setup QR code with the code verification field</em></p></blockquote><h3 id="signing-in-with-2fa" tabindex="-1">Signing In with 2FA <a class="header-anchor" href="#signing-in-with-2fa" aria-label="Permalink to &quot;Signing In with 2FA&quot;">​</a></h3><p>When signing in, after entering your email and password, an additional field asks for the TOTP code from your authenticator app.</p><h3 id="disable-2fa" tabindex="-1">Disable 2FA <a class="header-anchor" href="#disable-2fa" aria-label="Permalink to &quot;Disable 2FA&quot;">​</a></h3><p>Click <strong>Disable 2FA</strong> and confirm by entering a valid TOTP code.</p><hr><h2 id="notification-preferences" tabindex="-1">Notification Preferences <a class="header-anchor" href="#notification-preferences" aria-label="Permalink to &quot;Notification Preferences&quot;">​</a></h2><p>A table to choose, for each notification type, which channels are active (in-app and toast). See the <a href="./notifications.html#préférences-de-notifications">Notifications</a> page for details.</p><hr><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><p>Outbound webhook configuration. See the <a href="./notifications.html#webhooks">Notifications — Webhooks</a> page for details.</p><hr><h2 id="configuration-export-import" tabindex="-1">Configuration Export / Import <a class="header-anchor" href="#configuration-export-import" aria-label="Permalink to &quot;Configuration Export / Import&quot;">​</a></h2><p>Save and restore your configuration (rules and webhooks) in JSON format.</p><h3 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h3><ol><li>Click <strong>Export</strong></li><li>A <code>nid-config.json</code> file is downloaded</li></ol><p>The file contains your rules (associated by Gmail account email) and your webhooks. Sensitive data (tokens, secrets) is <strong>not</strong> included.</p><h3 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h3><ol><li>Click <strong>Import</strong></li><li>Select a previously exported JSON file</li><li>Rules are matched to your Gmail accounts by email correspondence</li><li>Webhooks are imported directly</li></ol><blockquote><p>📸 <em>Suggested screenshot: Export/Import section with the Export and Import buttons</em></p></blockquote><div class="warning custom-block"><p class="custom-block-title">Additive Import</p><p>Importing <strong>adds</strong> items without deleting existing ones. Importing the same file multiple times will create duplicates.</p></div><hr><h2 id="activity-log-audit-log" tabindex="-1">Activity Log (Audit Log) <a class="header-anchor" href="#activity-log-audit-log" aria-label="Permalink to &quot;Activity Log (Audit Log)&quot;">​</a></h2><p>The <strong>Activity Log</strong> section displays your recent actions in the application:</p><ul><li>Sign-ins and sign-outs</li><li>Rule creation, modification, and deletion</li><li>Bulk operations (deletion, archiving)</li><li>Configuration exports and imports</li></ul><blockquote><p>📸 <em>Suggested screenshot: activity log with actions, dates, and details</em></p></blockquote><hr><h2 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h2><p>The language selector is located in the <strong>navigation bar</strong> (at the top), next to the notification bell.</p><p>Available languages:</p><ul><li>🇫🇷 French (default)</li><li>🇬🇧 English</li></ul><p>The choice is persisted in the browser and maintained across sessions.</p><hr><h2 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h2><p>The <strong>dark / light theme</strong> toggle is located in the navigation bar, next to the language selector. The choice is persisted in the browser.</p>',51)])])}const p=t(n,[["render",r]]);export{g as __pageData,p as default};
